import ItemCardRight from "../ItemCardRight/ItemCardRight";
import ItemCardLeft from "../ItemCardLeft/ItemCardLeft";
import "./ItemCard.css";

const Card = window.ReactBootstrap.Card;
const Container = window.ReactBootstrap.Container;
const Row = window.ReactBootstrap.Row;
const Col = window.ReactBootstrap.Col;

export const ItemCard = ({ item }) => {
  let className = "x-card";
  if (item.sold_let) {
    className += " x-card-stc";
  }
  return (
    <Card
      className={className}
      data-miles={item.closest.miles}
      data-isflat={item.property_group_icon === "🏢"}
    >
      <Container fluid>
        <Row>
          <Col sm="5" style={{ padding: 0 }}>
            <ItemCardLeft item={item} />
          </Col>
          <Col sm="7" style={{ padding: "1rem", margin: "0" }}>
            <ItemCardRight item={item} />
          </Col>
        </Row>
      </Container>
    </Card>
  );
};

export default ItemCard;
